function calcTotal(order) {
  let price = 10;
  if (order.size === 'medium') {
    price = 14;
  }
  if (order.size === 'large') {
    price = 18;
  }
  let toppingsCost = 0;
  for (const t of order.toppings) {
    if (t === 'pepperoni') {
      toppingsCost = toppingsCost + 2;
    }
    if (t === 'mushrooms') {
      toppingsCost = toppingsCost + 1.5;
    }
  }
  price = price + toppingsCost;
  if (order.coupon === 'WELCOME10') {
    price = price * 0.9;
  }
  return price + price * 0.08;
}

function formatSummary(order, total) {
  let summary = 'Pedido: ' + order.size + ' pizza';
  if (order.toppings.length > 0) {
    summary = summary + ' con ' + order.toppings.join(', ');
  }
  summary = summary + ' | Total: $' + total.toFixed(2);
  return summary;
}

function processOrder(order) {
  const total = calcTotal(order);
  const summary = formatSummary(order, total);
  console.log(summary);
  return total;
}

